function compact(value, maxLen = 1200) {
  const v = String(value || '').replace(/\s+/g, ' ').trim();
  return v.length > maxLen ? v.slice(0, maxLen) : v;
}

function normalizeUrl(url) {
  const u = String(url || '').trim();
  if (!u || u === 'undefined' || u === 'null') return null;
  return u;
}

function titleFlags(title) {
  const t = String(title || '').toLowerCase().trim();
  return {
    looks_generic:
      /^home\b/.test(t) ||
      /^discover\b/.test(t) ||
      /^definition\b/.test(t) ||
      /^tickets?\b/.test(t) ||
      /^events?\b$/.test(t) ||
      /^veranstaltungen\b$/.test(t) ||
      /^termine\b$/.test(t),
    looks_ticket_platform:
      /adticket|eventim|getgo|ticketmaster|reservix|koelnticket/.test(t)
  };
}

const externalUrl = normalizeUrl($json.external_url);
const flags = titleFlags($json.title);

return {
  json: {
    entity_type: 'event',
    entity_id: $json.id,
    model_name: 'gemini-2.5-flash',
    ai_input: {
      title: compact($json.title, 200),
      description_de: compact($json.description_de, 1400),
      category: $json.category || null,
      city_id: $json.city_id || null,
      city_name: $json.city_name || null,
      venue_name: compact($json.venue_name, 160),
      starts_at: $json.starts_at || null,
      organizer_name: compact($json.organizer_name, 160),
      external_url: externalUrl,
      flags
    }
  }
};

