const txt = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let parsed;
try {
  parsed = JSON.parse(txt);
} catch (e) {
  parsed = {
    status: 'UNSURE',
    confidence: 0,
    reason_codes: ['INVALID_JSON'],
    is_plausible: false,
    suggested_action: 'send_to_moderation',
    notes: 'Gemini-Antwort konnte nicht als JSON geparst werden.'
  };
}

const allowedStatus = ['OK', 'REVIEW', 'REJECT', 'UNSURE'];
const allowedAction = ['keep', 'send_to_moderation', 'reject'];

return {
  json: {
    entity_type: 'event',
    entity_id: $items('Prepare AI Input')[0].json.entity_id,
    model_name: 'gemini-2.5-flash',
    ai_status: allowedStatus.includes(parsed.status) ? parsed.status : 'UNSURE',
    confidence_score: typeof parsed.confidence === 'number' ? Math.max(0, Math.min(1, parsed.confidence)) : 0,
    reason_codes_json: JSON.stringify(Array.isArray(parsed.reason_codes) ? parsed.reason_codes : ['NO_REASON_CODES']),
    explanation: parsed.notes || null,
    suggested_action: allowedAction.includes(parsed.suggested_action) ? parsed.suggested_action : 'send_to_moderation',
    raw_result_json: JSON.stringify(parsed)
  }
};
